def build_default_processor(logger: logging.Logger) -> MessageProcessor:
    p = MessageProcessor(logger=logger)

    def handle_echo(payload: Dict[str, Any], ctx: Dict[str, Any]) -> Any:
        logger.info("ECHO", extra={"payload": payload, "message_id": ctx.get("message_id")})
        return {"ok": True, "echo": payload}

    def handle_sleep(payload: Dict[str, Any], ctx: Dict[str, Any]) -> Any:
        seconds = payload.get("seconds", 1)
        try:
            seconds = float(seconds)
        except Exception:
            seconds = 1.0
        time.sleep(max(0.0, seconds))
        return {"ok": True, "slept": seconds}

    def default_handler(payload: Dict[str, Any], ctx: Dict[str, Any]) -> Any:
        logger.warning(
            "Default handler invoked (unregistered type)",
            extra={"type": payload.get("type"), "message_id": ctx.get("message_id")},
        )
        return {"ok": True, "handled_by": "default"}

    p.register("echo", handle_echo)
    p.register("sleep", handle_sleep)
    p.set_default(default_handler)
    return p


def _install_signal_handlers(worker: SQSWorker, logger: logging.Logger, grace_seconds: int) -> None:
    shutdown_started = {"t": None}

    def _handler(signum, frame):
        if shutdown_started["t"] is None:
            shutdown_started["t"] = time.time()
            logger.info("Shutdown signal received", extra={"signal": signum})
            worker.stop()
            return
        if time.time() - shutdown_started["t"] > max(0, grace_seconds):
            logger.error("Forcing exit after grace period")
            os._exit(2)

    for s in (signal.SIGINT, signal.SIGTERM):
        try:
            signal.signal(s, _handler)
        except Exception:
            pass


